const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

export function processScenario(scenario: Scenario): ScenarioResult {
  const results = scenario.steps.map((step) => {
    const items = step.items as Array<{ type: string }>;
    let premium = 0;
    for (const item of items) {
      premium += BASE_PREMIUMS[item.type];
    }
    premium = Math.ceil(premium * 1.1) + 5;
    return { premium };
  });
  return { results };
}

