import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quoting premiums", () => {
    it("should compute base premium for a single sword with processing fee", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 3, cursed: false },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      // sword base premium = 100G, first insurance +10% = 110G, + 5G fee = 115G
      expect(result.results[0].premium).toBe(115);
    });
    it("should compute base premium for each item type (amulet, staff, potion)", () => {
      const makeScenario = (type: string) => ({
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type, material: "steel", enchantment: 2, cursed: false },
            ],
          },
        ],
      });
      // amulet base 60G, +10% first = 66G, +5G fee = 71G
      expect(processScenario(makeScenario("amulet")).results[0].premium).toBe(71);
      // staff base 80G, +10% first = 88G, +5G fee = 93G
      expect(processScenario(makeScenario("staff")).results[0].premium).toBe(93);
      // potion base 40G, +10% first = 44G, +5G fee = 49G
      expect(processScenario(makeScenario("potion")).results[0].premium).toBe(49);
    });
    it.todo("should compute base premium for a single component");
    it.todo("should sum premiums for multiple different items");
    it.todo("should apply component bundle pricing for 3 alike components");
    it.todo("should add cursed item surcharge of 50%");
    it.todo("should add high enchantment surcharge of 30% for enchantment >= 5");
    it.todo("should apply loyalty discount of 20% for customers with >= 2 years");
    it.todo("should add initial assessment surcharge of 10% for first insurance");
    it.todo("should apply 15% discount on each contract after the first");
    it.todo("should round amounts in MHPCO's favor (ceiling)");
    it.todo("should combine multiple surcharges and discounts correctly");
  });

  describe("Processing claims", () => {
    it.todo("should apply 100G deductible per damage event");
    it.todo("should pay nothing when damage is less than deductible");
    it.todo("should reimburse damage to normal items fully minus deductible");
    it.todo("should reimburse dragon material items fully minus deductible");
    it.todo("should reimburse high enchantment items (>= 8) at 50% minus deductible");
    it.todo("should cap total payout at twice the insurance sum");
    it.todo("should track remaining cap across multiple claims on the same policy");
  });

  describe("CLI integration", () => {
    it.todo("should process a full scenario with quote and claims from JSON input");
  });
});

