              { type: "rune", material: "stone", enchantment: 0, cursed: false },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      // 3 alike components bundle = 60G base, +10% first = 66G, +5G fee = 71G
      expect(result.results[0].premium).toBe(71);
    });
    it("should add cursed item surcharge of 50%", () => {
      const scenario = {
        customer: { yearsWithMHPCO: 0 },
        steps: [
          {
            op: "quote" as const,
            items: [
              { type: "sword", material: "steel", enchantment: 2, cursed: true },
            ],
          },
        ],
      };
      const result = processScenario(scenario);
      // sword 100G + 50% cursed = 150G base, +10% first = 165G, +5G fee = 170G
      expect(result.results[0].premium).toBe(170);
    });
    it.todo("should add high enchantment surcharge of 30% for enchantment >= 5");
    it.todo("should apply loyalty discount of 20% for customers with >= 2 years");
    it.todo("should add initial assessment surcharge of 10% for first insurance");
    it.todo("should apply 15% discount on each contract after the first");
    it.todo("should round amounts in MHPCO's favor (ceiling)");
